function candidate(start, stop, value, list, compare, mode) {
  function isUpperChoice(flag) {
    if (flag === true || flag === 2) {
      return true;
    }
    if (typeof exports === "object" && exports && flag == exports.LEAST_UPPER_BOUND) {
      return true;
    }
    if (typeof flag === "string") {
      var normalized = flag.toLowerCase();
      return normalized === "upper" || normalized === "least_upper_bound" || normalized === "least-upper-bound";
    }
    return false;
  }

  var left = start;
  var right = stop;
  var preferUpper = isUpperChoice(mode);

  while (true) {
    var index = left + Math.floor((right - left) / 2);
    var ordering = compare(value, list[index], true);

    if (ordering === 0) {
      return index;
    }

    if (ordering > 0) {
      if (right - index > 1) {
        left = index;
        continue;
      }
      return preferUpper ? (right < list.length ? right : -1) : index;
    }

    if (index - left > 1) {
      right = index;
      continue;
    }

    return preferUpper ? index : (left < 0 ? -1 : left);
  }
}
